/**
 * SEO component that queries for data with
 * Gatsby's useStaticQuery React hook
 *
 * See: https://www.gatsbyjs.com/docs/how-to/querying-data/use-static-query/
 */

import * as React from "react"
import { useStaticQuery, graphql } from "gatsby"

function Seo({ description, title, image, lang, pathname, children }) {
  const { site } = useStaticQuery(
    graphql`
      query {
        site {
          siteMetadata {
            title
            description
            keywords
            author
            siteUrl
            siteUrlEs
            siteUrlEn
            siteUrlPt
            languages
            addressStreet
            addressLocality
            addressRegion
            addressCountry
            addressPostalCode
            sameAs
          }
        }
      }
    `
  )

  const metaDescription = description || site.siteMetadata.description
  const defaultTitle = site.siteMetadata?.title
  const baseUrl = site.siteMetadata?.siteUrl
  const pageLang = lang || "es"
  const canonicalPath = pathname || "/"
  const canonicalUrl = `${baseUrl}${canonicalPath}`

  const metaImage = image || `${baseUrl}/OG-image.png`

  // Build hreflang links from siteMetadata
  const langMap = {
    es: site.siteMetadata?.siteUrlEs || `${baseUrl}/es`,
    en: site.siteMetadata?.siteUrlEn || `${baseUrl}/en`,
    pt: site.siteMetadata?.siteUrlPt || `${baseUrl}/pt`,
  }

  const languages = site.siteMetadata?.languages
    ? site.siteMetadata.languages.split(",").map(l => l.trim())
    : ["es", "en", "pt"]

  // JSON-LD Structured Data for Tobacco Shop
  const structuredData = {
    "@context": "https://schema.org",
    "@type": "Store",
    name: defaultTitle,
    description: metaDescription,
    url: baseUrl,
    image: metaImage,
    founder: {
      "@type": "Person",
      name: site.siteMetadata?.author?.replace("@", "") || "Cigarros Brevas",
    },
    foundingDate: "1974",
    address: {
      "@type": "PostalAddress",
      streetAddress: site.siteMetadata?.addressStreet,
      addressLocality: site.siteMetadata?.addressLocality,
      addressRegion: site.siteMetadata?.addressRegion,
      postalCode: site.siteMetadata?.addressPostalCode,
      addressCountry: site.siteMetadata?.addressCountry,
    },
    sameAs: site.siteMetadata?.sameAs || [],
    knowsAbout: [
      "Cigarros artesanales colombianos",
      "Tabaco colombiano",
      "Puros de hoja entera",
      "Churchill, Torpedo, Robusto, Panetela, Purito, Número 5, Aromados",
    ],
    makesOffer: {
      "@type": "Offer",
      itemOffered: {
        "@type": "Product",
        name: "Cigarros Brevas",
        description: metaDescription,
        brand: {
          "@type": "Brand",
          name: "Brevas",
        },
      },
    },
  }

  return (
    <>
      <title>{defaultTitle ? `${title ? `${title} | ` : ""}${defaultTitle}` : title}</title>
      <meta name="description" content={metaDescription} />
      <meta name="keywords" content={site.siteMetadata?.keywords} />
      <meta name="author" content={site.siteMetadata?.author} />

      {/* Canonical URL */}
      <link rel="canonical" href={canonicalUrl} />

      {/* Open Graph */}
      <meta property="og:title" content={title || defaultTitle} />
      <meta property="og:description" content={metaDescription} />
      <meta property="og:type" content="website" />
      <meta property="og:image" content={metaImage} />
      <meta property="og:url" content={canonicalUrl} />
      <meta property="og:site_name" content={defaultTitle} />
      <meta property="og:locale" content={pageLang === "es" ? "es_CO" : pageLang === "en" ? "en_US" : "pt_BR"} />

      {/* Twitter Card */}
      <meta name="twitter:card" content="summary_large_image" />
      <meta name="twitter:title" content={title || defaultTitle} />
      <meta name="twitter:description" content={metaDescription} />
      <meta name="twitter:image" content={metaImage} />
      <meta name="twitter:site" content="@Diegoaupinzon" />
      <meta name="twitter:creator" content="@Diegoaupinzon" />

      {/* Hreflang links for multilingual SEO */}
      <link rel="alternate" hrefLang="x-default" href={`${baseUrl}${canonicalPath}`} />
      {languages.map((l) => (
        <link
          key={l}
          rel="alternate"
          hrefLang={l}
          href={`${langMap[l] || `${baseUrl}/${l}`}${canonicalPath}`}
        />
      ))}

      {/* JSON-LD Structured Data */}
      <script type="application/ld+json">
        {JSON.stringify(structuredData)}
      </script>

      {children}
    </>
  )
}

export default Seo
